import React, { useState, useEffect } from "react";
import { adminService } from "../services/adminService";
import {
  Search,
  RefreshCw,
  Trash2,
  Store,
  Clock,
  Tag,
  Eye,
  UserCheck,
  CheckCircle,
  XCircle,
  ShieldAlert,
} from "lucide-react";
import { Link } from "react-router-dom";

const Shops = () => {
  const [shops, setShops] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  const fetchShops = async () => {
    setLoading(true);
    try {
      const data = await adminService.getUsers("shopkeeper");
      setShops(data);
    } catch (error) {
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchShops();
  }, []);

  const handleVerify = async (id, isVerified) => {
    try {
      await adminService.verifyShopkeeper(id, isVerified);
      setShops(
        shops.map((s) =>
          s._id === id ? { ...s, isShopkeeperVerified: isVerified } : s,
        ),
      );
    } catch (error) {
      alert("Failed to update verification status");
    }
  };

  const handleDelete = async (id) => {
    if (
      window.confirm(
        "Are you sure you want to delete this shopkeeper and their shop?",
      )
    ) {
      try {
        await adminService.deleteUser(id);
        setShops(shops.filter((s) => s._id !== id));
      } catch (error) {
        alert("Failed to delete shop");
      }
    }
  };

  const handleActivate = async (id) => {
    if (window.confirm("Are you sure you want to reactivate this account?")) {
      try {
        await adminService.activateUser(id);
        setShops(
          shops.map((s) => (s._id === id ? { ...s, isDeleted: false } : s)),
        );
      } catch (error) {
        alert("Failed to reactivate account");
      }
    }
  };

  const filteredShops = shops.filter(
    (shop) =>
      (shop.shopDetails?.name || "")
        .toLowerCase()
        .includes(searchTerm.toLowerCase()) ||
      shop.name.toLowerCase().includes(searchTerm.toLowerCase()),
  );

  return (
    <div className="content-area animate-fade-in">
      <div className="section-header">
        <div>
          <h2>Shop Management</h2>
          <p className="section-subtitle">
            Monitor registered vendors and their stores
          </p>
        </div>
        <button className="primary-btn icon-text-btn" onClick={fetchShops}>
          <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
          Refresh
        </button>
      </div>

      <div className="search-bar-container glass-panel">
        <Search size={20} className="search-icon" />
        <input
          type="text"
          placeholder="Search by shop name or owner..."
          className="search-input"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="glass-panel" style={{ marginTop: "2rem" }}>
        {loading ? (
          <div className="table-loader">Loading shops...</div>
        ) : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>Shop Details</th>
                <th>Owner</th>
                <th>Category</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredShops.map((shop) => (
                <tr key={shop._id}>
                  <td>
                    <div className="user-info-cell">
                      <div className="user-avatar shop-avatar">
                        <img
                          src={
                            shop.image ||
                            `https://ui-avatars.com/api/?name=${encodeURIComponent(shop.name)}&background=random`
                          }
                          alt={shop.name}
                          style={{
                            width: "100%",
                            height: "100%",
                            borderRadius: "50%",
                            objectFit: "cover",
                          }}
                        />
                      </div>
                      <div>
                        <div className="user-name">
                          {shop.shopDetails?.name || "Unnamed Shop"}
                        </div>
                        <div className="user-email">
                          {shop.shopDetails?.businessType || "N/A"}
                        </div>
                      </div>
                    </div>
                  </td>
                  <td>
                    <div className="owner-info">
                      <div
                        className="owner-name"
                        style={{ display: "flex", alignItems: "center" }}
                      >
                        {shop.name}
                        {shop.isDeleted && shop.activationRequested ? (
                          <span
                            className="status-badge"
                            style={{
                              backgroundColor: "#f59e0b",
                              color: "white",
                              fontSize: "10px",
                              padding: "2px 6px",
                              marginLeft: "8px",
                            }}
                          >
                            Activation Requested
                          </span>
                        ) : shop.isDeleted ? (
                          <span
                            className="status-badge"
                            style={{
                              backgroundColor: "#ef4444",
                              color: "white",
                              fontSize: "10px",
                              padding: "2px 6px",
                              marginLeft: "8px",
                            }}
                          >
                            Deleted
                          </span>
                        ) : null}
                      </div>
                      <div className="owner-contact">{shop.email}</div>
                    </div>
                  </td>
                  <td>
                    <div className="category-badge">
                      <Tag size={12} />
                      {shop.shopDetails?.businessType || "General"}
                    </div>
                  </td>
                  <td>
                    {shop.isDeleted && shop.activationRequested ? (
                      <span
                        className="status-badge"
                        style={{
                          backgroundColor: "#f59e0b",
                          color: "white",
                          display: "inline-flex",
                          alignItems: "center",
                          gap: "6px",
                        }}
                      >
                        Activation Requested
                      </span>
                    ) : shop.isDeleted ? (
                      <span
                        className="status-badge"
                        style={{
                          backgroundColor: "#ef4444",
                          color: "white",
                          display: "inline-flex",
                          alignItems: "center",
                          gap: "6px",
                        }}
                      >
                        Deleted
                      </span>
                    ) : (
                      <span
                        className={`status-badge ${shop.isShopkeeperVerified ? "verified" : "pending"}`}
                        style={{
                          display: "inline-flex",
                          alignItems: "center",
                          gap: "6px",
                        }}
                      >
                        {!shop.isShopkeeperVerified && (
                          <ShieldAlert size={14} />
                        )}
                        {shop.isShopkeeperVerified
                          ? "Verified"
                          : "Pending Verification"}
                      </span>
                    )}
                  </td>
                  <td>
                    <div style={{ display: "flex", gap: "0.5rem" }}>
                      <Link
                        to={`/products?shop=${encodeURIComponent(shop.shopDetails?.name || "")}`}
                        className="action-btn"
                        style={{
                          color: "var(--primary)",
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                        }}
                        title="View Shop Products"
                      >
                        <Eye size={18} />
                      </Link>
                      {shop.isDeleted ? (
                        <button
                          className="action-btn verify"
                          onClick={() => handleActivate(shop._id)}
                          title="Reactivate Shopkeeper"
                        >
                          <UserCheck size={18} />
                        </button>
                      ) : (
                        <>
                          {!shop.isShopkeeperVerified ? (
                            <button
                              className="action-btn verify"
                              onClick={() => handleVerify(shop._id, true)}
                              title="Verify Shopkeeper"
                            >
                              <CheckCircle size={18} />
                            </button>
                          ) : (
                            <button
                              className="action-btn unverify"
                              onClick={() => handleVerify(shop._id, false)}
                              title="Unverify Shopkeeper"
                            >
                              <XCircle size={18} />
                            </button>
                          )}
                          <button
                            className="action-btn delete"
                            onClick={() => handleDelete(shop._id)}
                            title="Delete Account"
                          >
                            <Trash2 size={18} />
                          </button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredShops.length === 0 && (
                <tr>
                  <td colSpan="5" className="empty-table-msg">
                    No shops found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default Shops;
